import { useEffect, useMemo, useState } from "react";
import {
  LineChart,
  Line,
  ResponsiveContainer,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  Legend,
} from "recharts";
import { fetchYahooHistory } from "@/lib/yahooProxy";
import { fetchBinanceKlines } from "@/lib/binanceProxy";
import { fetchForexHistory } from "@/lib/forexProxy";
import { hybridPredict } from "@/lib/physics/hybrid";
import type { MarketAsset } from "@/lib/markets";

interface Props {
  coin: MarketAsset;
}

type RangeKey = "1h" | "1w" | "1mo" | "1y";

const RANGES: Array<{
  key: RangeKey;
  label: string;
  interval: string;
  range: string;
  predictFraction: number;
  binanceInterval: string;
  binanceLimit: number;
  forexLimit: number;
}> = [
  {
    key: "1h",
    label: "1 hour",
    interval: "1m",
    range: "1d",
    predictFraction: 0.25,
    binanceInterval: "1m",
    binanceLimit: 60,
    forexLimit: 60,
  },
  {
    key: "1w",
    label: "1 week",
    interval: "15m",
    range: "1mo",
    predictFraction: 0.2,
    binanceInterval: "15m",
    binanceLimit: 700,
    forexLimit: 200,
  },
  {
    key: "1mo",
    label: "1 month",
    interval: "1h",
    range: "3mo",
    predictFraction: 0.2,
    binanceInterval: "1h",
    binanceLimit: 720,
    forexLimit: 365,
  },
  {
    key: "1y",
    label: "1 year",
    interval: "1d",
    range: "5y",
    predictFraction: 0.2,
    binanceInterval: "1d",
    binanceLimit: 365,
    forexLimit: 365,
  },
];

interface Row {
  ts: number;
  actual: number | null;
  predicted: number | null;
}

export function ComparisonPanel({ coin }: Props) {
  const [range, setRange] = useState<RangeKey>("1w");
  const [rows, setRows] = useState<Row[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    const cfg = RANGES.find((r) => r.key === range)!;
    const truncate = range === "1h" ? 60 : undefined;

    void (async () => {
      try {
        let hist: Array<{ ts: number; price: number }> = [];

        if (coin.market === "crypto" && coin.binanceSymbol) {
          try {
            hist = await fetchBinanceKlines({
              data: {
                symbol: coin.binanceSymbol,
                interval: cfg.binanceInterval,
                limit: cfg.binanceLimit,
              },
            });
          } catch {
            /* fall through */
          }
          if (hist.length < 30) {
            const sym = coin.yahooSymbol || `${coin.symbol.toUpperCase()}-USD`;
            try {
              hist = await fetchYahooHistory({
                data: { symbol: sym, interval: cfg.interval, range: cfg.range },
              });
            } catch {
              /* ignore */
            }
          }
        } else if (coin.market === "forex") {
          const base = coin.forexBase ?? coin.symbol.slice(0, 3).toUpperCase();
          const quote = coin.forexQuote ?? coin.symbol.slice(3, 6).toUpperCase() ?? "USD";
          try {
            hist = await fetchForexHistory({
              data: { base, quote, limit: cfg.forexLimit, mode: "free", premiumApiKey: "" },
            });
          } catch {
            /* fall through */
          }
          if (hist.length < 30 && coin.yahooSymbol) {
            hist = await fetchYahooHistory({
              data: { symbol: coin.yahooSymbol, interval: cfg.interval, range: cfg.range },
            });
          }
        } else {
          const symbolCandidates = buildYahooCandidates(coin);
          const requestPlan: Array<{ interval: string; range: string }> = [
            { interval: cfg.interval, range: cfg.range },
            { interval: "5m", range: "5d" },
            { interval: "15m", range: "1mo" },
            { interval: "1h", range: "3mo" },
            { interval: "1d", range: "1y" },
          ];
          for (const symbol of symbolCandidates) {
            for (const req of requestPlan) {
              hist = await fetchYahooHistory({
                data: { symbol, interval: req.interval, range: req.range },
              });
              if (hist.length > 30) break;
            }
            if (hist.length > 30) break;
          }
        }

        if (cancelled) return;
        if (!hist.length) {
          setRows([]);
          setError(
            "No historical data returned for this asset yet. Try a different range or asset.",
          );
          setLoading(false);
          return;
        }
        const sliced = truncate ? hist.slice(-truncate) : hist;
        // Split into train + holdout. Train on first part, predict the holdout
        // window and compare to the actual values from the same window.
        const holdoutLen = Math.max(5, Math.floor(sliced.length * cfg.predictFraction));
        const train = sliced.slice(0, sliced.length - holdoutLen).map((r) => r.price);
        const holdout = sliced.slice(sliced.length - holdoutLen);
        if (train.length < 20) {
          setRows([]);
          setError("Not enough training data for this range.");
          setLoading(false);
          return;
        }
        const pred = hybridPredict(train, holdoutLen);
        const out: Row[] = [];
        // Plot full actual line
        for (let i = 0; i < sliced.length; i++) {
          out.push({ ts: sliced[i].ts, actual: sliced[i].price, predicted: null });
        }
        // Overlay predicted line on the holdout window
        for (let i = 0; i < holdoutLen; i++) {
          const idx = sliced.length - holdoutLen + i;
          out[idx].predicted = pred.forecast[i].price;
        }
        // Anchor predicted line to last train point so the line is continuous
        const anchorIdx = sliced.length - holdoutLen - 1;
        if (anchorIdx >= 0) out[anchorIdx].predicted = sliced[anchorIdx].price;
        setRows(out);
        setLoading(false);
      } catch (e) {
        if (cancelled) return;
        setError(String((e as Error)?.message ?? e));
        setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [coin.id, coin.market, coin.symbol, coin.yahooSymbol, range]);

  const stats = useMemo(() => {
    const valid = rows.filter((r) => r.actual != null && r.predicted != null);
    if (!valid.length) return null;
    let sumAbs = 0;
    let sumPct = 0;
    let directionHits = 0;
    let directionTotal = 0;
    for (let i = 1; i < valid.length; i++) {
      const dA = (valid[i].actual ?? 0) - (valid[i - 1].actual ?? 0);
      const dP = (valid[i].predicted ?? 0) - (valid[i - 1].predicted ?? 0);
      if (Math.sign(dA) === Math.sign(dP)) directionHits++;
      directionTotal++;
      sumAbs += Math.abs((valid[i].actual ?? 0) - (valid[i].predicted ?? 0));
      sumPct += Math.abs(
        ((valid[i].actual ?? 0) - (valid[i].predicted ?? 0)) / Math.max(1e-9, valid[i].actual ?? 1),
      );
    }
    return {
      mae: sumAbs / valid.length,
      mape: (sumPct / valid.length) * 100,
      dirAcc: directionTotal ? (directionHits / directionTotal) * 100 : 0,
    };
  }, [rows]);

  return (
    <div className="panel p-4">
      <div className="flex items-center justify-between mb-3 flex-wrap gap-2">
        <div>
          <h3 className="font-display font-semibold text-sm">Actual vs Predicted</h3>
          <p className="text-[10px] text-muted-foreground">
            Backtest: train on the first portion, forecast the last{" "}
            {(RANGES.find((r) => r.key === range)?.predictFraction ?? 0) * 100}% and compare.
          </p>
        </div>
        <div className="flex gap-1">
          {RANGES.map((r) => (
            <button
              key={r.key}
              onClick={() => setRange(r.key)}
              className={`px-2.5 py-1 rounded text-[11px] border transition-colors ${
                range === r.key
                  ? "bg-primary text-primary-foreground border-primary"
                  : "bg-card border-border text-muted-foreground hover:text-foreground"
              }`}
            >
              {r.label}
            </button>
          ))}
        </div>
      </div>

      {stats && (
        <div className="grid grid-cols-3 gap-2 mb-2 text-xs">
          <Stat label="Direction acc." value={`${stats.dirAcc.toFixed(1)}%`} />
          <Stat label="MAPE" value={`${stats.mape.toFixed(2)}%`} />
          <Stat
            label="MAE"
            value={stats.mae < 1 ? stats.mae.toExponential(2) : stats.mae.toFixed(2)}
          />
        </div>
      )}

      <div className="h-[280px]">
        {loading ? (
          <div className="h-full flex items-center justify-center text-xs text-muted-foreground">
            <div className="inline-block w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin mr-2" />
            Loading historical data…
          </div>
        ) : error ? (
          <div className="h-full flex items-center justify-center text-xs text-destructive">
            {error}
          </div>
        ) : rows.length === 0 ? (
          <div className="h-full flex items-center justify-center text-xs text-muted-foreground">
            No data.
          </div>
        ) : (
          <div style={{ width: "100%", height: "100%", overflow: "hidden" }}>
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={rows} margin={{ left: 8, right: 8, top: 8, bottom: 0 }}>
                <CartesianGrid stroke="oklch(0.28 0.04 265)" strokeOpacity={0.3} />
                <XAxis
                  dataKey="ts"
                  tickFormatter={(v) => {
                    const d = new Date(v);
                    if (range === "1h")
                      return d.toLocaleTimeString([], {
                        hour: "2-digit",
                        minute: "2-digit",
                        hour12: false,
                      });
                    if (range === "1w")
                      return d.toLocaleDateString([], { month: "short", day: "numeric" });
                    if (range === "1mo")
                      return d.toLocaleDateString([], { month: "short", day: "numeric" });
                    return d.toLocaleDateString([], { month: "short", year: "2-digit" });
                  }}
                  tick={{ fill: "oklch(0.65 0.03 255)", fontSize: 10 }}
                />
                <YAxis
                  domain={["auto", "auto"]}
                  tick={{ fill: "oklch(0.65 0.03 255)", fontSize: 10 }}
                  width={56}
                  tickFormatter={(v) => (v < 1 ? Number(v).toExponential(1) : Number(v).toFixed(2))}
                />
                <Tooltip
                  labelFormatter={(v) => new Date(Number(v)).toLocaleString()}
                  formatter={(value) => {
                    const n = Number(value);
                    if (!Number.isFinite(n)) return "—";
                    return n < 1 ? n.toExponential(3) : n.toFixed(4);
                  }}
                  contentStyle={{
                    background: "oklch(0.18 0.04 265)",
                    border: "1px solid oklch(0.28 0.04 265)",
                    fontSize: 11,
                  }}
                />
                <Legend wrapperStyle={{ fontSize: 11 }} />
                <Line
                  type="linear"
                  dataKey="actual"
                  name="Actual"
                  stroke="var(--bull)"
                  dot={false}
                  strokeWidth={1.6}
                />
                <Line
                  type="linear"
                  dataKey="predicted"
                  name="Predicted"
                  stroke="var(--quantum)"
                  dot={false}
                  strokeWidth={1.6}
                  strokeDasharray="4 3"
                  connectNulls
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>
    </div>
  );
}

function buildYahooCandidates(coin: MarketAsset): string[] {
  const out = new Set<string>();
  if (coin.yahooSymbol) out.add(coin.yahooSymbol.toUpperCase());
  const s = coin.symbol.toUpperCase().replace(/[^A-Z0-9^]/g, "");
  if (s) {
    if (coin.market === "nse") out.add(`${s}.NS`);
    if (coin.market === "bse") out.add(`${s}.BO`);
    if (coin.market === "crypto") out.add(`${s}-USD`);
  }
  if (coin.id === "nifty-50") out.add("^NSEI");
  if (coin.id === "sensex") out.add("^BSESN");
  if (coin.id === "banknifty") out.add("^NSEBANK");
  return Array.from(out);
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded border border-border px-2 py-1.5">
      <div className="text-muted-foreground text-[10px] uppercase">{label}</div>
      <div className="text-foreground font-semibold font-mono">{value}</div>
    </div>
  );
}

// Demo trading panel — paper trades only, persisted to localStorage.
// Mirrors the "Place Trade" + Positions/Log/Stats panel from the v2 mockup.

import { useEffect, useMemo, useState } from "react";
import type { MarketAsset } from "@/lib/markets";
import type { HybridResult } from "@/lib/physics/hybrid";

type Direction = "long" | "short";

interface Position {
  id: number;
  pair: string;
  dir: Direction;
  entry: number;
  size: number;
  lev: number;
  stop: number;
  tp: number;
  qty: number;
  time: string;
}

interface ClosedTrade {
  time: string;
  pair: string;
  dir: Direction;
  entry: number;
  exit: number;
  pnl: number;
  correct: boolean;
}

interface Account {
  balance: number;
  realPnl: number;
  totalTrades: number;
  positions: Position[];
  trades: ClosedTrade[];
}

const STORAGE_KEY = "qe_demo_account_v1";
const INITIAL: Account = {
  balance: 10000,
  realPnl: 0,
  totalTrades: 0,
  positions: [],
  trades: [],
};

function loadAccount(): Account {
  if (typeof window === "undefined") return INITIAL;
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return INITIAL;
    return { ...INITIAL, ...JSON.parse(raw) };
  } catch {
    return INITIAL;
  }
}

function saveAccount(a: Account) {
  if (typeof window === "undefined") return;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(a));
}

function fmtPrice(v: number): string {
  if (v >= 1000) return v.toLocaleString(undefined, { maximumFractionDigits: 2 });
  if (v >= 1) return v.toFixed(3);
  if (v >= 0.01) return v.toFixed(5);
  return v.toExponential(3);
}

interface Props {
  coin: MarketAsset;
  currentPrice: number;
  prediction: HybridResult | null;
  /** Recent prices (most recent last) used to size stop/TP via ATR. */
  recentPrices?: number[];
}

// Per-market default ATR multipliers for SL/TP. Crypto futures move much
// further than NSE equities or major FX in the same wall-clock window, so a
// "2σ stop" means very different things across markets.
const MARKET_RISK: Record<string, { slMult: number; tpMult: number; minBps: number }> = {
  crypto: { slMult: 1.8, tpMult: 3.0, minBps: 25 }, // 0.25% min stop
  nse: { slMult: 1.4, tpMult: 2.4, minBps: 35 }, // 0.35% min stop (slower)
  bse: { slMult: 1.4, tpMult: 2.4, minBps: 35 },
  forex: { slMult: 1.2, tpMult: 2.0, minBps: 8 }, // 8 bps ~ typical FX stop
};

export function DemoTrading({ coin, currentPrice, prediction, recentPrices }: Props) {
  const [mounted, setMounted] = useState(false);
  const [acct, setAcct] = useState<Account>(INITIAL);
  const [direction, setDirection] = useState<Direction>("long");
  const [size, setSize] = useState<number>(100);
  const [lev, setLev] = useState<number>(2);
  const [entry, setEntry] = useState<number>(currentPrice || 0);
  const [customSL, setCustomSL] = useState<number | null>(null);
  const [customTP, setCustomTP] = useState<number | null>(null);
  const [tab, setTab] = useState<"pos" | "log" | "stats">("pos");

  useEffect(() => {
    setMounted(true);
    setAcct(loadAccount());
  }, []);

  // Reset entry & custom SL/TP when the selected coin/market changes
  useEffect(() => {
    setEntry(currentPrice || 0);
    setCustomSL(null);
    setCustomTP(null);
  }, [coin.market, coin.symbol]);

  useEffect(() => {
    if (currentPrice > 0) setEntry((e) => (e === 0 ? currentPrice : e));
  }, [currentPrice]);

  useEffect(() => {
    if (!mounted) return;
    saveAccount(acct);
  }, [acct, mounted]);

  // Auto-fill direction from current model bias
  useEffect(() => {
    if (prediction?.direction === "up") setDirection("long");
    else if (prediction?.direction === "down") setDirection("short");
  }, [prediction?.direction]);

  // When direction flips, drop manual SL/TP so they don't sit on the wrong side
  useEffect(() => {
    setCustomSL(null);
    setCustomTP(null);
  }, [direction]);

  // ATR-style range from recent prices (true range = high-low over last N bars).
  // Falls back to GARCH σ if no recent series is provided.
  const atr = useMemo(() => {
    if (recentPrices && recentPrices.length >= 14) {
      const slice = recentPrices.slice(-30);
      let sum = 0;
      for (let i = 1; i < slice.length; i++) sum += Math.abs(slice[i] - slice[i - 1]);
      return sum / Math.max(1, slice.length - 1);
    }
    return prediction?.garch.sigma ?? 0;
  }, [recentPrices, prediction?.garch.sigma]);

  const risk = MARKET_RISK[coin.market] ?? MARKET_RISK.crypto;
  // Floor stop at minBps so micro-volatility regimes don't produce a 1-tick stop.
  const minMove = entry * (risk.minBps / 10000);
  const slDist = Math.max(atr * risk.slMult, minMove);
  const tpDist = Math.max(atr * risk.tpMult, minMove * 1.6);
  const suggestedStop = direction === "long" ? entry - slDist : entry + slDist;
  const suggestedTp = direction === "long" ? entry + tpDist : entry - tpDist;
  const stop = customSL ?? suggestedStop;
  const tp = customTP ?? suggestedTp;
  const riskU = entry > 0 ? size * lev * (Math.abs(entry - stop) / entry) : 0;
  const rewardU = entry > 0 ? size * lev * (Math.abs(tp - entry) / entry) : 0;
  const rrRatio = riskU > 0 ? rewardU / riskU : 0;
  const kelly = 0.275; // half-Kelly @ 55% wr, 1.5 RR

  const unrealized = useMemo(() => {
    if (currentPrice === 0) return 0;
    return acct.positions.reduce((sum, p) => {
      const dirSign = p.dir === "short" ? -1 : 1;
      return sum + p.qty * (currentPrice - p.entry) * dirSign * p.lev;
    }, 0);
  }, [acct.positions, currentPrice]);

  const openTrade = () => {
    if (entry <= 0 || size <= 0) return;
    const pos: Position = {
      id: Date.now(),
      pair: coin.symbol.toUpperCase().includes("/")
        ? coin.symbol.toUpperCase()
        : coin.symbol.toUpperCase(),
      dir: direction,
      entry,
      size,
      lev,
      stop,
      tp,
      qty: (size * lev) / entry,
      time: new Date().toLocaleTimeString(),
    };
    setAcct((a) => ({
      ...a,
      positions: [...a.positions, pos],
      totalTrades: a.totalTrades + 1,
    }));
  };

  const closePos = (id: number) => {
    setAcct((a) => {
      const i = a.positions.findIndex((p) => p.id === id);
      if (i < 0) return a;
      const p = a.positions[i];
      const exit = currentPrice;
      const dirSign = p.dir === "short" ? -1 : 1;
      const pnl = +(p.qty * (exit - p.entry) * dirSign * p.lev).toFixed(2);
      const priceWentUp = exit > p.entry;
      const correct = (p.dir === "long" && priceWentUp) || (p.dir === "short" && !priceWentUp);
      const trade: ClosedTrade = {
        time: new Date().toLocaleTimeString(),
        pair: p.pair,
        dir: p.dir,
        entry: p.entry,
        exit,
        pnl,
        correct,
      };
      const positions = [...a.positions];
      positions.splice(i, 1);
      return {
        ...a,
        positions,
        trades: [trade, ...a.trades].slice(0, 100),
        balance: a.balance + pnl,
        realPnl: a.realPnl + pnl,
      };
    });
  };

  const resetAccount = () => {
    if (confirm("Reset demo account to $10,000?")) setAcct(INITIAL);
  };

  // Stats
  const stats = useMemo(() => {
    const t = acct.trades;
    if (t.length === 0) return null;
    const pnls = t.map((x) => x.pnl);
    const wins = pnls.filter((p) => p > 0);
    const losses = pnls.filter((p) => p <= 0);
    const wr = wins.length / pnls.length;
    const avgW = wins.reduce((a, b) => a + b, 0) / Math.max(1, wins.length);
    const avgL = Math.abs(losses.reduce((a, b) => a + b, 0)) / Math.max(1, losses.length);
    const pf = avgL > 0 ? (avgW * wins.length) / (avgL * losses.length) : 0;
    const mean = pnls.reduce((a, b) => a + b, 0) / pnls.length;
    const std = Math.sqrt(pnls.reduce((a, b) => a + (b - mean) ** 2, 0) / pnls.length) || 1;
    const sharpe = (mean / std) * Math.sqrt(pnls.length);
    let peak = 0,
      dd = 0,
      cum = 0;
    for (const p of pnls.slice().reverse()) {
      cum += p;
      peak = Math.max(peak, cum);
      dd = Math.min(dd, cum - peak);
    }
    const dirAcc = t.filter((x) => x.correct).length / t.length;
    const rr = avgL > 0 ? avgW / avgL : 0;
    return { wr, pf, sharpe, dd, dirAcc, rr };
  }, [acct.trades]);

  const isLong = direction === "long";
  const colorOk = "hsl(142 76% 50%)";
  const colorBad = "hsl(0 84% 60%)";

  return (
    <div className="panel p-4 space-y-3">
      <div className="flex items-center justify-between">
        <div className="flex items-baseline gap-2">
          <h3 className="font-display font-semibold text-foreground text-sm">Demo Trade</h3>
          <span className="text-[10px] uppercase tracking-wider text-primary font-mono">
            {coin.symbol.toUpperCase()}
          </span>
          <span className="text-[9px] uppercase tracking-wider text-muted-foreground">
            {coin.market}
          </span>
        </div>
        <button
          onClick={resetAccount}
          className="text-[10px] uppercase tracking-wider text-muted-foreground hover:text-foreground"
        >
          Reset
        </button>
      </div>

      {/* Direction */}
      <div>
        <div className="text-[9px] uppercase tracking-wider text-muted-foreground mb-1">
          Direction
        </div>
        <div className="flex gap-1">
          <button
            onClick={() => setDirection("long")}
            className="flex-1 py-1.5 rounded text-xs font-bold border transition-colors"
            style={
              isLong
                ? { background: "hsl(142 76% 50% / 0.15)", borderColor: colorOk, color: colorOk }
                : {
                    background: "transparent",
                    borderColor: "hsl(var(--border))",
                    color: "hsl(var(--muted-foreground))",
                  }
            }
          >
            LONG
          </button>
          <button
            onClick={() => setDirection("short")}
            className="flex-1 py-1.5 rounded text-xs font-bold border transition-colors"
            style={
              !isLong
                ? { background: "hsl(0 84% 60% / 0.15)", borderColor: colorBad, color: colorBad }
                : {
                    background: "transparent",
                    borderColor: "hsl(var(--border))",
                    color: "hsl(var(--muted-foreground))",
                  }
            }
          >
            SHORT
          </button>
        </div>
      </div>

      {/* Market Risk Profile Display */}
      <div className="p-2 rounded border border-border/50 bg-card/50 text-[9px] space-y-1">
        <div className="flex justify-between text-muted-foreground">
          <span>Volatility (ATR):</span>
          <span className="font-mono font-bold text-foreground">{atr.toFixed(8)}</span>
        </div>
        <div className="flex justify-between text-muted-foreground">
          <span>Market Risk:</span>
          <span className="font-mono font-bold text-foreground">
            {risk.slMult.toFixed(1)}σ SL · {risk.tpMult.toFixed(1)}σ TP · {risk.minBps} bps min
          </span>
        </div>
        <div className="flex justify-between text-muted-foreground">
          <span>Suggested SL/TP:</span>
          <span className="font-mono font-bold text-foreground">
            {fmtPrice(suggestedStop)} / {fmtPrice(suggestedTp)}
          </span>
        </div>
      </div>

      {/* Inputs */}
      <div className="grid grid-cols-3 gap-2">
        <NumField label="Size (USDT)" value={size} onChange={setSize} min={1} />
        <NumField label="Leverage" value={lev} onChange={setLev} min={1} max={50} />
        <NumField label="Entry" value={entry} onChange={setEntry} step="any" />
      </div>

      {/* Manual SL / TP */}
      <div className="grid grid-cols-2 gap-2">
        <div>
          <div className="flex items-center justify-between mb-1">
            <span className="text-[9px] uppercase tracking-wider text-muted-foreground">
              Stop Loss
            </span>
            <button
              onClick={() => setCustomSL(null)}
              className="text-[9px] uppercase tracking-wider text-primary/70 hover:text-primary"
              title="Use suggested 2σ stop"
            >
              auto
            </button>
          </div>
          <input
            type="number"
            value={Number.isFinite(stop) ? +stop.toFixed(8) : 0}
            step="any"
            onChange={(e) => setCustomSL(parseFloat(e.target.value) || 0)}
            className="w-full px-2 py-1.5 rounded bg-card border border-border text-xs font-mono outline-none focus:border-primary transition-colors"
            style={{ color: colorBad }}
          />
        </div>
        <div>
          <div className="flex items-center justify-between mb-1">
            <span className="text-[9px] uppercase tracking-wider text-muted-foreground">
              Take Profit
            </span>
            <button
              onClick={() => setCustomTP(null)}
              className="text-[9px] uppercase tracking-wider text-primary/70 hover:text-primary"
              title="Use suggested 3σ TP"
            >
              auto
            </button>
          </div>
          <input
            type="number"
            value={Number.isFinite(tp) ? +tp.toFixed(8) : 0}
            step="any"
            onChange={(e) => setCustomTP(parseFloat(e.target.value) || 0)}
            className="w-full px-2 py-1.5 rounded bg-card border border-border text-xs font-mono outline-none focus:border-primary transition-colors"
            style={{ color: colorOk }}
          />
        </div>
      </div>

      {/* Risk box */}
      <div className="grid grid-cols-2 gap-1 p-2 rounded border border-border bg-card text-[10px]">
        <div>
          <span className="text-muted-foreground">Risk: </span>
          <span className="font-bold" style={{ color: colorBad }}>
            ${riskU.toFixed(2)}
          </span>
        </div>
        <div>
          <span className="text-muted-foreground">Reward: </span>
          <span className="font-bold" style={{ color: colorOk }}>
            ${rewardU.toFixed(2)}
          </span>
        </div>
        <div>
          <span className="text-muted-foreground">R:R: </span>
          <span className="text-primary font-bold">{rrRatio.toFixed(2)}</span>
        </div>
        <div>
          <span className="text-muted-foreground">Kelly: </span>
          <span className="text-primary font-bold">{(kelly * 100).toFixed(1)}%</span>
        </div>
      </div>

      <button
        onClick={openTrade}
        className="w-full py-2.5 rounded font-display font-bold text-sm tracking-wide transition-opacity hover:opacity-90"
        style={{ background: isLong ? colorOk : colorBad, color: "#040710" }}
      >
        {isLong ? "OPEN LONG" : "OPEN SHORT"}
      </button>

      {/* Tabs */}
      <div className="flex border-b border-border -mx-4 px-4">
        {(["pos", "log", "stats"] as const).map((t) => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className="px-3 py-1.5 text-[10px] uppercase tracking-wider transition-colors border-b-2"
            style={
              tab === t
                ? { color: "hsl(var(--primary))", borderColor: "hsl(var(--primary))" }
                : { color: "hsl(var(--muted-foreground))", borderColor: "transparent" }
            }
          >
            {t === "pos" ? `Positions (${acct.positions.length})` : t === "log" ? "Log" : "Stats"}
          </button>
        ))}
      </div>

      {tab === "pos" && (
        <div className="space-y-2 max-h-64 overflow-y-auto">
          {acct.positions.length === 0 && (
            <div className="text-center text-[10px] text-muted-foreground py-4">
              No open positions
            </div>
          )}
          {acct.positions.map((p) => {
            const dirSign = p.dir === "short" ? -1 : 1;
            const upnl = currentPrice > 0 ? p.qty * (currentPrice - p.entry) * dirSign * p.lev : 0;
            const pos = upnl >= 0;
            return (
              <div key={p.id} className="rounded border border-border bg-card p-2 text-[11px]">
                <div className="flex justify-between items-center mb-1">
                  <span className="font-display font-bold text-xs">{p.pair}</span>
                  <span
                    className="px-1.5 rounded text-[9px] font-bold"
                    style={{
                      background:
                        p.dir === "long" ? "hsl(142 76% 50% / 0.2)" : "hsl(0 84% 60% / 0.2)",
                      color: p.dir === "long" ? colorOk : colorBad,
                    }}
                  >
                    {p.dir.toUpperCase()} ×{p.lev}
                  </span>
                </div>
                <div className="grid grid-cols-2 gap-1">
                  <div className="text-muted-foreground">
                    Entry <span className="text-foreground">${fmtPrice(p.entry)}</span>
                  </div>
                  <div className="text-muted-foreground">
                    Now <span className="text-foreground">${fmtPrice(currentPrice)}</span>
                  </div>
                  <div className="text-muted-foreground">
                    Stop <span className="text-foreground">${fmtPrice(p.stop)}</span>
                  </div>
                  <div className="text-muted-foreground">
                    TP <span className="text-foreground">${fmtPrice(p.tp)}</span>
                  </div>
                </div>
                <div className="flex justify-between items-center mt-1.5">
                  <span className="text-[9px] text-muted-foreground">{p.time}</span>
                  <span className="font-bold" style={{ color: pos ? colorOk : colorBad }}>
                    {pos ? "+" : ""}${Math.abs(upnl).toFixed(2)}
                  </span>
                </div>
                <button
                  onClick={() => closePos(p.id)}
                  className="w-full mt-1.5 py-1 rounded border border-border text-[10px] hover:border-destructive hover:text-destructive transition-colors"
                >
                  Close Position
                </button>
              </div>
            );
          })}
        </div>
      )}

      {tab === "log" && (
        <div className="max-h-64 overflow-y-auto">
          {acct.trades.length === 0 ? (
            <div className="text-center text-[10px] text-muted-foreground py-4">No trades yet</div>
          ) : (
            acct.trades.map((t, i) => (
              <div
                key={i}
                className="flex justify-between py-1.5 border-b border-border text-[10px]"
              >
                <span className="text-muted-foreground">{t.time}</span>
                <span>{t.pair}</span>
                <span
                  style={{ color: t.dir === "long" ? colorOk : colorBad }}
                  className="font-bold"
                >
                  {t.dir[0].toUpperCase()}
                </span>
                <span style={{ color: t.pnl >= 0 ? colorOk : colorBad }} className="font-bold">
                  {t.pnl >= 0 ? "+" : ""}${Math.abs(t.pnl).toFixed(2)}
                </span>
              </div>
            ))
          )}
        </div>
      )}

      {tab === "stats" && (
        <div className="grid grid-cols-2 gap-2 text-[11px]">
          {stats ? (
            <>
              <Stat label="Win Rate" value={`${(stats.wr * 100).toFixed(1)}%`} />
              <Stat label="Profit Factor" value={stats.pf.toFixed(2)} />
              <Stat label="Sharpe" value={stats.sharpe.toFixed(2)} />
              <Stat label="Max DD" value={`$${stats.dd.toFixed(2)}`} color={colorBad} />
              <Stat label="Dir. Accuracy" value={`${(stats.dirAcc * 100).toFixed(1)}%`} />
              <Stat label="Avg RR" value={stats.rr.toFixed(2)} />
            </>
          ) : (
            <div className="col-span-2 text-center text-[10px] text-muted-foreground py-4">
              Close a trade to see stats
            </div>
          )}
        </div>
      )}

      {/* Account bar */}
      <div className="grid grid-cols-2 gap-2 pt-3 border-t border-border">
        <Stat
          label="Balance"
          value={`$${acct.balance.toFixed(2)}`}
          color={acct.balance >= 10000 ? colorOk : colorBad}
        />
        <Stat
          label="Unrealized P&L"
          value={`${unrealized >= 0 ? "+" : ""}$${Math.abs(unrealized).toFixed(2)}`}
          color={unrealized >= 0 ? colorOk : colorBad}
        />
        <Stat
          label="Realized P&L"
          value={`${acct.realPnl >= 0 ? "+" : ""}$${Math.abs(acct.realPnl).toFixed(2)}`}
          color={acct.realPnl >= 0 ? colorOk : colorBad}
        />
        <Stat label="Total Trades" value={acct.totalTrades.toString()} />
      </div>
    </div>
  );
}

function NumField({
  label,
  value,
  onChange,
  min,
  max,
  step,
}: {
  label: string;
  value: number;
  onChange: (v: number) => void;
  min?: number;
  max?: number;
  step?: number | "any";
}) {
  return (
    <div>
      <div className="text-[9px] uppercase tracking-wider text-muted-foreground mb-1">{label}</div>
      <input
        type="number"
        value={value}
        min={min}
        max={max}
        step={step as number | undefined}
        onChange={(e) => onChange(parseFloat(e.target.value) || 0)}
        className="w-full px-2 py-1.5 rounded bg-card border border-border text-xs font-mono outline-none focus:border-primary transition-colors"
      />
    </div>
  );
}

function Stat({ label, value, color }: { label: string; value: string; color?: string }) {
  return (
    <div className="rounded bg-card p-2">
      <div className="text-[9px] uppercase tracking-wider text-muted-foreground">{label}</div>
      <div className="font-bold text-sm" style={{ color: color ?? "hsl(var(--foreground))" }}>
        {value}
      </div>
    </div>
  );
}

import { useMemo } from "react";
import type { HybridResult } from "@/lib/physics/hybrid";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Card } from "@/components/ui/card";

interface Props {
  prediction: HybridResult;
  currentPrice: number;
  recentPrices: number[];
  dataQualityScore: number;
  llmSignal: { bias: number; confidence: number; rationale: string };
}

export function StrategicPlanPanel({
  prediction,
  currentPrice,
  recentPrices,
  dataQualityScore,
  llmSignal,
}: Props) {
  // 1. Multi-Agent Simulation: Analyze competing strategies
  const agentAnalysis = useMemo(() => {
    if (recentPrices.length < 10) return null;

    // Momentum trader: follows recent trend
    const recentReturn =
      (recentPrices[recentPrices.length - 1] - recentPrices[Math.max(0, recentPrices.length - 6)]) /
      recentPrices[Math.max(0, recentPrices.length - 6)];
    const momentumSignal =
      recentReturn > 0.001 ? "long" : recentReturn < -0.001 ? "short" : "neutral";
    const momentumConfidence = Math.min(0.95, Math.abs(recentReturn) * 100);

    // Mean-reversion trader: bets on reversion to average
    const sma20 =
      recentPrices.slice(-20).reduce((a, b) => a + b, 0) / Math.min(20, recentPrices.length);
    const deviation = (currentPrice - sma20) / sma20;
    const meanReversionSignal = deviation > 0.02 ? "short" : deviation < -0.02 ? "long" : "neutral";
    const meanReversionConfidence = Math.min(0.95, Math.abs(deviation) * 80);

    // Market maker: follows volatility & volume (simulated from price variance)
    const volatility = calculateVolatility(recentPrices.slice(-20));
    const makerSignal =
      volatility > 0.015 ? "widen_spread" : volatility < 0.005 ? "tighten_spread" : "neutral";
    const makerConfidence = Math.min(0.95, volatility * 100);

    // Consensus detector: how many agree?
    const agreements = [
      momentumSignal === "long",
      meanReversionSignal === "long",
      prediction.direction === "up",
      llmSignal.bias > 0.1,
    ].filter(Boolean).length;

    const convergence = agreements / 4; // 0 to 1

    return {
      momentum: { signal: momentumSignal, confidence: momentumConfidence },
      meanReversion: { signal: meanReversionSignal, confidence: meanReversionConfidence },
      marketMaker: { signal: makerSignal, confidence: makerConfidence },
      convergence, // Nash equilibrium stability
      agreements,
    };
  }, [recentPrices, currentPrice, prediction.direction, llmSignal.bias]);

  // 2. Nash Equilibrium Detection
  const equilibriumAnalysis = useMemo(() => {
    if (!agentAnalysis) return null;

    const { convergence, agreements } = agentAnalysis;

    // Stable equilibrium: high convergence + quality data + model confidence
    const stability = convergence * dataQualityScore * prediction.hybridConfidence;
    const isStable = stability > 0.45;

    // Equilibrium type
    let equilibriumType = "UNSTABLE";
    if (stability > 0.7) equilibriumType = "STRONGLY STABLE";
    else if (stability > 0.5) equilibriumType = "STABLE";
    else if (stability > 0.35) equilibriumType = "WEAKLY STABLE";

    // Opportunity detection: when equilibrium breaks
    const breakChance = 1 - stability;
    const opportunityRank = agreements >= 3 ? "HIGH" : agreements === 2 ? "MEDIUM" : "LOW";

    return {
      stability,
      isStable,
      equilibriumType,
      breakChance,
      opportunityRank,
    };
  }, [agentAnalysis, dataQualityScore, prediction.hybridConfidence]);

  // 3. Strategic Position Sizing (Kelly Criterion + Minimax)
  const positionSizing = useMemo(() => {
    if (!agentAnalysis || !equilibriumAnalysis) return null;

    const winRate = prediction.hybridConfidence;
    const lossRate = 1 - winRate;
    const expectedReturn = (prediction.finalPrice - currentPrice) / currentPrice;

    // Simplified Kelly: f* = (bp - q) / b, where b = profit/loss ratio, p = win prob, q = loss prob
    const profitLossRatio = Math.abs(expectedReturn);
    const kellyFraction = Math.max(0, (profitLossRatio * winRate - lossRate) / profitLossRatio);

    // Minimax: minimize worst-case loss (conservative)
    const minimaxFraction = Math.min(0.5, winRate - 0.25); // 0.25 is a safety buffer

    // Recommended sizing (blended)
    const recommendedSize = Math.min(kellyFraction, minimaxFraction) * 0.85; // 85% of optimal
    const maxLossIfWrong = currentPrice * recommendedSize * 0.05; // 5% stop loss

    // Risk-adjusted position
    const riskProfile = equilibriumAnalysis.isStable ? "AGGRESSIVE" : "CONSERVATIVE";
    const adjustedSize = riskProfile === "AGGRESSIVE" ? recommendedSize : recommendedSize * 0.6;

    return {
      kelly: kellyFraction,
      minimax: minimaxFraction,
      recommended: recommendedSize,
      adjusted: adjustedSize,
      maxLossIfWrong,
      riskProfile,
      expectedReturn: (expectedReturn * 100).toFixed(2),
    };
  }, [agentAnalysis, equilibriumAnalysis, prediction, currentPrice]);

  // 4. Volatility Opportunity Signal
  const volatilityOpportunity = useMemo(() => {
    if (recentPrices.length < 10) return null;

    const recentVol = calculateVolatility(recentPrices.slice(-10));
    const historicalVol = calculateVolatility(recentPrices.slice(-50));

    const volRatio = historicalVol > 0 ? recentVol / historicalVol : 1;
    const isVolExpanding = volRatio > 1.2;
    const isVolContracting = volRatio < 0.8;

    // Opportunity: expand when vol is low, contract when vol is high
    let opportunity = "NEUTRAL";
    if (isVolContracting && (agentAnalysis?.convergence ?? 0) > 0.5) opportunity = "LOW_VOL_SETUP";
    if (isVolExpanding && prediction.hybridConfidence > 0.6) opportunity = "HIGH_VOL_TRADE";

    return {
      recent: recentVol,
      historical: historicalVol,
      ratio: volRatio,
      trend: isVolExpanding ? "EXPANDING" : isVolContracting ? "CONTRACTING" : "NEUTRAL",
      opportunity,
    };
  }, [recentPrices, agentAnalysis, prediction.hybridConfidence]);

  // 5. Ensemble Model Weighting
  const ensembleWeights = useMemo(() => {
    const wRec = prediction.weights as Record<string, number>;
    const weights = {
      arima: prediction.weights.arima * (agentAnalysis?.convergence ?? 0.5),
      garch: wRec["garch"] ? wRec["garch"] * (volatilityOpportunity?.ratio ?? 1) : 0.15,
      hmm: prediction.weights.hmm * (equilibriumAnalysis?.stability ?? 0.5),
      entropy: prediction.weights.entropy * dataQualityScore,
      hurst: prediction.weights.hurst * (agentAnalysis?.convergence ?? 0.5),
      neural: prediction.weights.neural * prediction.hybridConfidence,
      llm: llmSignal.confidence,
      indicators: prediction.weights.indicators
        ? prediction.weights.indicators * (agentAnalysis?.convergence ?? 0.5)
        : 0.12,
    };

    const total = Object.values(weights).reduce((a, b) => a + b, 0);
    const normalized = Object.entries(weights).reduce(
      (acc, [key, value]) => ({
        ...acc,
        [key]: total > 0 ? ((value / total) * 100).toFixed(1) : "0.0",
      }),
      {} as Record<string, string>,
    );

    return normalized;
  }, [
    prediction.weights,
    agentAnalysis,
    equilibriumAnalysis,
    volatilityOpportunity,
    dataQualityScore,
    llmSignal.confidence,
  ]);

  // 6. Overall Strategic Signal — Hybrid model + technical indicator fusion
  const strategicSignal = useMemo(() => {
    if (!agentAnalysis || !equilibriumAnalysis || !positionSizing) return null;

    // --- Hybrid model directional score, signed in [-1, 1] ---
    const expectedReturn = (prediction.finalPrice - currentPrice) / Math.max(1e-9, currentPrice);
    const sigmaPct = Math.max(1e-9, prediction.garch.sigma / Math.max(1e-9, currentPrice));
    const modelDirScore = Math.max(-1, Math.min(1, expectedReturn / (sigmaPct * 2)));
    const regimeBias = prediction.hmm.stateProbs[2] - prediction.hmm.stateProbs[0]; // bull - bear
    const modelScore = 0.6 * modelDirScore + 0.4 * regimeBias;

    // --- Technical indicator score, signed in [-1, 1] ---
    // indicators.bias already aggregates VWAP-z, EMA slope, MACD
    const techBias = Math.max(-1, Math.min(1, prediction.indicators.bias));
    const momentumPush =
      agentAnalysis.momentum.signal === "long"
        ? 0.5
        : agentAnalysis.momentum.signal === "short"
          ? -0.5
          : 0;
    const meanRevPush =
      agentAnalysis.meanReversion.signal === "long"
        ? 0.25
        : agentAnalysis.meanReversion.signal === "short"
          ? -0.25
          : 0;
    const techScore = Math.max(
      -1,
      Math.min(1, 0.6 * techBias + 0.3 * momentumPush + 0.1 * meanRevPush),
    );

    // --- Fused signed score (hybrid 55%, technicals 45%) ---
    const fusedScore = 0.55 * modelScore + 0.45 * techScore;
    const agreement = Math.sign(modelScore) === Math.sign(techScore) && Math.sign(modelScore) !== 0;

    // --- Market regime: Bullish / Bearish / Sideways ---
    let marketRegime: "BULLISH" | "BEARISH" | "SIDEWAYS" = "SIDEWAYS";
    if (fusedScore > 0.18) marketRegime = "BULLISH";
    else if (fusedScore < -0.18) marketRegime = "BEARISH";

    // Confidence-weighted gate for actionable trade
    const components = {
      convergence: agentAnalysis.convergence,
      equilibrium: equilibriumAnalysis.stability,
      confidence: prediction.hybridConfidence,
      dataQuality: dataQualityScore,
    };
    const compositeScore =
      Object.values(components).reduce((a, b) => a + b, 0) / Object.keys(components).length;

    // --- BUY / SELL / HOLD recommendation ---
    // Require: clear direction (|fused| > 0.18), reasonable confidence,
    // and ideally model + technicals agreeing.
    let recommendation: "BUY" | "SELL" | "HOLD" | "AVOID" = "HOLD";
    const actionGate = compositeScore > 0.55 && Math.abs(fusedScore) > 0.18;
    const strongGate = compositeScore > 0.65 && Math.abs(fusedScore) > 0.3 && agreement;
    if (compositeScore < 0.35) recommendation = "AVOID";
    else if (strongGate || actionGate) {
      recommendation = fusedScore > 0 ? "BUY" : "SELL";
    }

    const signalStrength = Math.min(1, Math.abs(fusedScore) * 0.6 + (compositeScore - 0.5) * 0.8);

    return {
      recommendation,
      marketRegime,
      fusedScore,
      modelScore,
      techScore,
      agreement,
      compositeScore,
      signalStrength: Math.max(0, signalStrength),
      components,
    };
  }, [
    agentAnalysis,
    equilibriumAnalysis,
    positionSizing,
    prediction.finalPrice,
    prediction.garch.sigma,
    prediction.hmm.stateProbs,
    prediction.indicators.bias,
    prediction.hybridConfidence,
    currentPrice,
    dataQualityScore,
  ]);

  if (
    !agentAnalysis ||
    !equilibriumAnalysis ||
    !positionSizing ||
    !volatilityOpportunity ||
    !strategicSignal
  ) {
    return (
      <div className="panel p-4 text-sm text-muted-foreground">
        <div className="inline-block w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin mr-2" />
        Computing strategic analysis…
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Overall Strategic Signal */}
      <Alert
        className={`border-2 ${
          strategicSignal.recommendation === "BUY"
            ? "border-bull bg-bull/10"
            : strategicSignal.recommendation === "SELL"
              ? "border-bear bg-bear/10"
              : "border-border"
        }`}
      >
        <AlertDescription className="space-y-2">
          <div className="flex items-center justify-between">
            <div>
              <div className="text-[11px] uppercase tracking-wider text-muted-foreground">
                Strategic Recommendation
              </div>
              <div
                className="text-lg font-display font-bold"
                style={{
                  color:
                    strategicSignal.recommendation === "BUY"
                      ? "var(--bull)"
                      : strategicSignal.recommendation === "SELL"
                        ? "var(--bear)"
                        : "var(--foreground)",
                }}
              >
                {strategicSignal.recommendation}
              </div>
              <div className="text-[10px] text-muted-foreground mt-0.5">
                Hybrid model + technical indicators{" "}
                {strategicSignal.agreement ? "✓ agree" : "⚠ diverge"}
              </div>
            </div>
            <div className="text-right">
              <div className="text-[10px] uppercase tracking-wider text-muted-foreground">
                Market Outlook
              </div>
              <div
                className="text-lg font-display font-bold"
                style={{
                  color:
                    strategicSignal.marketRegime === "BULLISH"
                      ? "var(--bull)"
                      : strategicSignal.marketRegime === "BEARISH"
                        ? "var(--bear)"
                        : "var(--foreground)",
                }}
              >
                {strategicSignal.marketRegime}
              </div>
              <div className="text-[10px] text-muted-foreground mt-0.5">
                Strength {(strategicSignal.signalStrength * 100).toFixed(0)}%
              </div>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2 text-[10px]">
            <div className="bg-card p-1.5 rounded border border-border/50">
              <div className="uppercase text-muted-foreground text-[8px]">Hybrid Model Score</div>
              <div
                className={`font-bold ${strategicSignal.modelScore > 0 ? "text-bull" : strategicSignal.modelScore < 0 ? "text-bear" : "text-foreground"}`}
              >
                {strategicSignal.modelScore > 0 ? "+" : ""}
                {(strategicSignal.modelScore * 100).toFixed(0)}
              </div>
            </div>
            <div className="bg-card p-1.5 rounded border border-border/50">
              <div className="uppercase text-muted-foreground text-[8px]">Technicals Score</div>
              <div
                className={`font-bold ${strategicSignal.techScore > 0 ? "text-bull" : strategicSignal.techScore < 0 ? "text-bear" : "text-foreground"}`}
              >
                {strategicSignal.techScore > 0 ? "+" : ""}
                {(strategicSignal.techScore * 100).toFixed(0)}
              </div>
            </div>
          </div>
